 */
export default function useSingleQuery<T, E = T>(
  url: string,
  mapFunction?: ((arg: E) => T) | null,
  shouldExecute?: boolean,
  params: URLSearchParams = {} as URLSearchParams
): {data: T | undefined, isLoading: boolean, fetch: () => () => void} {

